#include <stdio.h>
#include <stdint.h>

int64_t gcd_int64(int64_t a, int64_t b) {
    while (b != 0) {
        int64_t r = a % b;
        a = b;
        b = r;
    }
    return a;
}

int main() {
    int T;
    if (scanf("%d", &T) != 1) return 0;
    while (T--) {
        int64_t N, M;
        scanf("%lld %lld", &N, &M);
        printf("%lld\n", gcd_int64(N, M));
    }
    return 0;
}

