    input.push(line);
}).on('close', function() {
    let T = parseInt(input.shift());
    let i = 0;
    while (T--) {
        let [N, M] = input[i++].split(' ').map(x => parseInt(x));
        let a = N;
        let b = M;
        while (b != 0) {
            let r = a % b;
            a = b;
            b = r;
        }
        console.log(a);
    }
});
